# Deobfuscated Code

After resolving all the string lookups, base64 decoding, and renaming variables, here is the fully deobfuscated code:

```javascript
// Constants
var TAU = 6.283;           // a0_0x72fc0b - Full circle in radians (2π)
var GOLDEN_RATIO = 1.618;  // a0_0x40042a - Golden ratio φ
var SQRT_HALF = 0.707;     // a0_0xc9463b - √(1/2) ≈ sin(45°) or cos(45°)

// Physics configuration
var physicsConfig = {                    // a0_0x5e495a
    attractionStrength: 4000,            // 'attraction' → 0xFA0
    springCoeff: 0.004,                  // 'springCoeff' (spring coefficient)
    amplification: 0.92,                 // 'amplification' (velocity damping factor)
    gravityStrength: 0.0003,             // 'gravityStrength' (centering gravity)
    maxParticles: 40,                    // 'maxParticles' (stream particle cap)
    streamDecay: 0.04,                   // 'streamDecay'
    theta: 0.06                          // 'theta' (camera interpolation speed)
};

// --- NODES ---

var hubNode = {              // a0_0x125afa
    id: 'hub',
    label: 'Hub',
    r: 26,                   // 0x1A
    x: 400,                  // 0x190
    y: 300,                  // 0x12C
    vx: 0,
    vy: 0
};

var alphaNode = {            // a0_0x41c4c4
    id: 'alpha',
    label: 'Alpha',
    r: 16,                   // 0x10
    x: 500,                  // 0x1F4
    y: 200,                  // 0xC8
    vx: 0,
    vy: 0
};

var betaNode = {             // a0_0x52d1a3
    id: 'beta',
    label: 'Beta',
    r: 16,                   // 0x10
    x: 300,                  // 0x12C
    y: 400,                  // 0x190
    vx: 0,
    vy: 0
};

var gammaNode = {            // a0_0x57d4c9
    id: 'gamma',
    label: 'Gamma',
    r: 14,                   // 0x0E
    x: 250,                  // 0xFA
    y: 180,                  // 0xB4
    vx: 0,
    vy: 0
};

var deltaNode = {            // a0_0x247912
    id: 'delta',
    label: 'Delta',
    r: 14,                   // 0x0E
    x: 550,                  // 0x226
    y: 380,                  // 0x17C
    vx: 0,
    vy: 0
};

var epsilonNode = {          // a0_0x268672
    id: 'epsilon',
    label: 'Epsilon',
    r: 12,                   // 0x0C
    x: 350,                  // 0x15E
    y: 150,                  // 0x96
    vx: 0,
    vy: 0
};

var nodes = [hubNode, alphaNode, betaNode, gammaNode, deltaNode, epsilonNode];

// --- SPRING EDGES ---

var edges = [
    { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },   // 0xA0
    { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },   // 0xA0
    { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },   // 0xAA
    { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },   // 0xAA
    { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },   // 0xB4
    { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 }, // 0xC8
    { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 }, // 0xDC
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }  // 0xC8
];

// --- CAMERA ---

var camera = {          // a0_0x5c885a (current camera state)
    x: 400,
    y: 300,
    zoom: 1
};

var cameraTarget = {    // a0_0x2b275f (target camera state)
    x: 400,
    y: 300,
    zoom: 1
};

// --- PARTICLES ---

var particles = [];     // a0_0x4b8ef5
var frameCount = 0;     // a0_0x464d76

// --- UTILITY: Find node by ID ---
function findNodeById(nodeId) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === nodeId) return nodes[i];
    }
    return null;
}

// --- PHYSICS SIMULATION ---
function updatePhysics() {
    // 1) Coulomb-style repulsion between all node pairs
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var repulsionForce = physicsConfig.attractionStrength / (dist * dist);
            var fx = (dx / dist) * repulsionForce;
            var fy = (dy / dist) * repulsionForce;

            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2) Hooke's law spring forces along edges
    for (var e = 0; e < edges.length; e++) {
        var nodeA = findNodeById(edges[e].a);
        var nodeB = findNodeById(edges[e].b);
        if (!nodeA || !nodeB) continue;

        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[e].rest;
        var springForce = (edges[e].k || physicsConfig.springCoeff) * displacement;

        nodeA.vx += (dx / dist) * springForce;
        nodeA.vy += (dy / dist) * springForce;
        nodeB.vx -= (dx / dist) * springForce;
        nodeB.vy -= (dy / dist) * springForce;
    }

    // 3) Centering gravity, velocity damping, and position integration
    for (var n = 0; n < nodes.length; n++) {
        // Centering gravity toward (400, 300)
        nodes[n].vx += (400 - nodes[n].x) * physicsConfig.gravityStrength;
        nodes[n].vy += (300 - nodes[n].y) * physicsConfig.gravityStrength;

        // Velocity damping (amplification = 0.92, so 8% energy loss per tick)
        nodes[n].vx *= physicsConfig.amplification;
        nodes[n].vy *= physicsConfig.amplification;

        // Euler integration
        nodes[n].x += nodes[n].vx;
        nodes[n].y += nodes[n].vy;
    }
}

// --- PARTICLE SPAWNING ---
function spawnParticle() {
    if (particles.length >= physicsConfig.maxParticles) return;

    // Pick a random node as the emission source
    var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];

    // Random angle around full circle, random speed
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT_HALF;

    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,   // 0x320 + rand * 0x4B0
        size: 0.8 + (Math.random() * GOLDEN_RATIO) * SQRT_HALF
    });
}

// --- PARTICLE UPDATE ---
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];

        // Age the particle
        p.age++;

        // Remove if expired
        if (p.age > p.maxAge) {
            particles.splice(i, 1);
            continue;
        }

        // Apply drag/decay to velocity
        p.vx *= (1 - physicsConfig.streamDecay * 0.125);
        p.vy *= (1 - physicsConfig.streamDecay * 0.125);

        // Euler integration
        p.x += p.vx;
        p.y += p.vy;
    }
}

// --- CAMERA INTERPOLATION ---
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * physicsConfig.theta;
    camera.y += (cameraTarget.y - camera.y) * physicsConfig.theta;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * physicsConfig.theta;
}

// --- MAIN LOOP ---
function mainLoop() {
    updatePhysics();
    updateParticles();
    updateCamera();

    // Spawn a particle every 3rd frame
    if (frameCount % 3 === 0) {
        spawnParticle();
    }
    frameCount++;
}

setInterval(mainLoop, 16);  // ~60 FPS
```

